record_types.code:
type gsl_bst_avl_node is record
   avl_link : gsl_bst_avl_node_array10109;
   avl_data    : System.Address;
   avl_balance : aliased signed_char;
end record;

type gsl_bst_avl_table is record
   avl_root : access gsl_bst_avl_node;
   avl_compare : access function
     (arg1 : System.Address; arg2 : System.Address; arg3 : System.Address)
      return int;
   avl_param : System.Address;
   avl_alloc : access constant gsl.bst_types
     .gsl_bst_allocator;
   avl_count      : aliased size_t;
   avl_generation : aliased unsigned_long;
end record;

type gsl_bst_avl_traverser is record
   avl_table : access constant gsl_bst_avl_table;
   avl_node : access gsl_bst_avl_node;
   avl_stack : gsl_bst_avl_traverser_array10119;
   avl_height     : aliased size_t;
   avl_generation : aliased unsigned_long;
end record;
